22	  const [recommending, setRecommending] = useState(false);
23	  const [recommendError, setRecommendError] = useState<string | null>(null);
24	  const [submitting, setSubmitting] = useState(false);
25	  const [submitError, setSubmitError] = useState<string | null>(null);
26	
27	  const handleRecommend = async () => {
28	    if (!requirement.trim()) return;
29	    setRecommending(true);
30	    setRecommendError(null);
31	    setRecommendations([]);
32	    try {
33	      type RecommendResponse =
34	        | { ok: true; data: { recommendations: Recommendation[]; topPick: string } }
35	        | { ok: false; fallback: string };
36	      const res = await apiFetch<RecommendResponse>(
37	        "/api/ai/recommend",
38	        { method: "POST", body: { requirement } },
39	      );
40	      if (res.ok) {
41	        setRecommendations(res.data.recommendations);
42	        if (res.data.recommendations.length > 0) {
43	          setSelectedModelId(res.data.recommendations[0].modelId);
44	        }
45	      } else {
46	        setRecommendError(res.fallback);
47	      }
48	    } catch (err) {
49	      setRecommendError(err instanceof Error ? err.message : "推荐失败，请稍后重试");
50	    } finally {
51	      setRecommending(false);
52	    }
53	  };
54	
55	  const handleSubmit = async () => {
56	    if (!selectedModelId || !reason.trim()) return;
57	    setSubmitting(true);
58	    setSubmitError(null);
59	    try {
60	      const ticket = await apiFetch<{ id: string }>("/api/tickets/apply", {
61	        method: "POST",
62	        body: { modelId: selectedModelId, reason },
63	      });
64	      router.push(`/tickets/${ticket.id}`);
65	    } catch (err) {
66	      setSubmitError(err instanceof Error ? err.message : "提交失败");
67	    } finally {
68	      setSubmitting(false);
69	    }
70	  };
71	
72	  return (
73	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-2xl mx-auto w-full">
